SELECT F.FILE_ID AS fileId, F.ENTRPRS_MBER_ID AS entrprsmberId, F.FILE_SN AS fileSn, F.STRE_FILE_NM AS streFileNm, F.ORIGNL_FILE_NM AS orignlFileNm, F.FILE_STRE_PATH AS fileStrePath, F.FILE_MG AS fileMg, F.FILE_EXTSN AS fileExtsn, F.FILE_CN AS fileCn, TO_CHAR(F.REGIST_PNTTM, 'YYYY.MM.DD HH24:MI:SS') AS regDate FROM COMTNENTRPRSMBERFILE F INNER JOIN COMTNENTRPRSMBER M ON M.ENTRPRS_MBER_ID = F.ENTRPRS_MBER_ID WHERE F.ENTRPRS_MBER_ID = #{entrprsmberId}
AND M.PROJECT_ID = #{projectId}
ORDER BY F.FILE_SN ASC, F.REGIST_PNTTM ASC

SELECT F.FILE_ID AS fileId, F.ENTRPRS_MBER_ID AS entrprsmberId, F.FILE_SN AS fileSn, F.STRE_FILE_NM AS streFileNm, F.ORIGNL_FILE_NM AS orignlFileNm, F.FILE_STRE_PATH AS fileStrePath, F.FILE_MG AS fileMg, F.FILE_EXTSN AS fileExtsn, F.FILE_CN AS fileCn, TO_CHAR(F.REGIST_PNTTM, 'YYYY.MM.DD HH24:MI:SS') AS regDate FROM COMTNENTRPRSMBERFILE F INNER JOIN COMTNENTRPRSMBER M ON M.ENTRPRS_MBER_ID = F.ENTRPRS_MBER_ID WHERE F.FILE_ID = #{fileId}
AND M.PROJECT_ID = #{projectId}
LIMIT 1

