SELECT
        ENTRPRS_MBER_PASSWORD          entrprsMberPassword 
FROM    COMTNENTRPRSMBER
WHERE ESNTL_ID=#{uniqId}

AND PROJECT_ID = #{projectId}

SELECT * FROM ( SELECT ROWNUM AS RN, T.* FROM ( SELECT TRIM(INSTT_ID) AS INSTT_ID, INSTT_NM AS CMPNY_NM, ENTRPRS_SE_CODE AS ENTRPRS_SE_CODE, BIZRNO AS BIZRNO, REPRSNT_NM AS CXFC, INSTT_STTUS AS JOIN_STAT FROM COMTNINSTTINFO I WHERE (#{keyword} = '' OR INSTT_NM LIKE '%' || #{keyword} || '%' OR BIZRNO LIKE '%' || #{keyword} || '%')
AND PROJECT_ID = #{projectId}
AND TRIM(INSTT_ID) = TRIM(#{insttId})
AND ENTRPRS_SE_CODE IN ('E', 'P')
AND ENTRPRS_SE_CODE = 'C'
AND ENTRPRS_SE_CODE = 'G'
AND ENTRPRS_SE_CODE = 'E'
AND ENTRPRS_SE_CODE = 'P'
AND ENTRPRS_SE_CODE = 'G'
AND ENTRPRS_SE_CODE = UPPER(#{membershipType})
AND ENTRPRS_SE_CODE = #{entrprsSeCode}
AND INSTT_STTUS = #{status}
ORDER BY INSTT_NM ASC ) T ) Z WHERE Z.RN BETWEEN #{offset} + 1 AND #{offset} + #{pageSize}

SELECT F.FILE_ID AS fileId, TRIM(F.INSTT_ID) AS insttId, F.FILE_SN AS fileSn, F.STRE_FILE_NM AS streFileNm, F.ORIGNL_FILE_NM AS orignlFileNm, F.FILE_STRE_PATH AS fileStrePath, F.FILE_MG AS fileMg, F.FILE_EXTSN AS fileExtsn, F.FILE_CN AS fileCn, TO_CHAR(F.REGIST_PNTTM, 'YYYY.MM.DD HH24:MI:SS') AS regDate FROM COMTNINSTTFILE F INNER JOIN COMTNINSTTINFO I ON TRIM(I.INSTT_ID) = TRIM(F.INSTT_ID) WHERE TRIM(F.INSTT_ID) = TRIM(#{insttId})
AND I.PROJECT_ID = #{projectId}
ORDER BY F.FILE_SN ASC, F.REGIST_PNTTM ASC

SELECT F.FILE_ID AS fileId, F.INSTT_ID AS insttId, F.FILE_SN AS fileSn, F.STRE_FILE_NM AS streFileNm, F.ORIGNL_FILE_NM AS orignlFileNm, F.FILE_STRE_PATH AS fileStrePath, F.FILE_MG AS fileMg, F.FILE_EXTSN AS fileExtsn, F.FILE_CN AS fileCn, TO_CHAR(F.REGIST_PNTTM, 'YYYY.MM.DD HH24:MI:SS') AS regDate FROM COMTNINSTTFILE F INNER JOIN COMTNINSTTINFO I ON TRIM(I.INSTT_ID) = TRIM(F.INSTT_ID) WHERE F.FILE_ID = #{fileId}
AND I.PROJECT_ID = #{projectId}
LIMIT 1

SELECT COUNT(1) FROM COMTNINSTTINFO
WHERE (#{keyword} = '' OR INSTT_NM LIKE '%' || #{keyword} || '%' OR BIZRNO LIKE '%' || #{keyword} || '%')

    AND PROJECT_ID = #{projectId}


    AND INSTT_ID = #{insttId}




            AND ENTRPRS_SE_CODE IN ('E', 'P')


            AND ENTRPRS_SE_CODE = 'C'


            AND ENTRPRS_SE_CODE = 'G'


            AND ENTRPRS_SE_CODE = 'E'


            AND ENTRPRS_SE_CODE = 'P'


            AND ENTRPRS_SE_CODE = 'G'


            AND ENTRPRS_SE_CODE = UPPER(#{membershipType})




    AND ENTRPRS_SE_CODE = #{entrprsSeCode}


    AND INSTT_STTUS = #{status}

SELECT INSTT_ID as INSTT_ID, INSTT_NM as CMPNY_NM, ENTRPRS_SE_CODE as ENTRPRS_SE_CODE, BIZRNO as BIZRNO, REPRSNT_NM as CXFC FROM COMTNINSTTINFO WHERE (INSTT_NM LIKE '%' || #{searchKeyword} || '%' OR BIZRNO LIKE '%' || #{searchKeyword} || '%') AND INSTT_STTUS IN ('P', 'A')
AND PROJECT_ID = #{projectId}
UNION ALL SELECT '' as INSTT_ID, CMPNY_NM as CMPNY_NM, 'ENT' as ENTRPRS_SE_CODE, BIZRNO as BIZRNO, APPLCNT_NM as CXFC FROM COMTNENTRPRSMBER WHERE (CMPNY_NM LIKE '%' || #{searchKeyword} || '%' OR BIZRNO LIKE '%' || #{searchKeyword} || '%') AND ENTRPRS_MBER_STTUS IN ('P', 'A') AND BIZRNO NOT IN (SELECT BIZRNO FROM COMTNINSTTINFO WHERE 1=1
AND PROJECT_ID = #{projectId}
)
AND PROJECT_ID = #{projectId}
ORDER BY CMPNY_NM ASC

SELECT * FROM ( SELECT rownum rn, TB.* FROM ( SELECT ESNTL_ID as UNIQ_ID, 'USR02' as USER_TY, ENTRPRS_MBER_ID as ENTRPRSMBER_ID, CMPNY_NM as CMPNY_NM, APPLCNT_NM as APPLCNT_NM, APPLCNT_EMAIL_ADRES as APPLCNT_EMAIL_ADRES, AREA_NO as AREA_NO, ENTRPRS_MIDDLE_TELNO as ENTRPRS_MIDDLE_TELNO, ENTRPRS_END_TELNO as ENTRPRS_END_TELNO, ENTRPRS_SE_CODE as ENTRPRS_SE_CODE, INSTT_ID as INSTT_ID, GROUP_ID as GROUP_ID, ENTRPRS_MBER_STTUS as ENTRPRS_MBER_STTUS, RJCT_RSN as rjctRsn, TO_CHAR(RJCT_PNTTM, 'YYYY.MM.DD HH24:MI:SS') as rjctPnttm, TO_CHAR(SBSCRB_DE, 'YYYY-MM-DD HH24:MI:SS') as SBSCRB_DE, BIZ_REG_FILE_PATH as BIZ_REG_FILE_PATH FROM COMTNENTRPRSMBER WHERE 1=1
AND PROJECT_ID = #{projectId}
AND TRIM(COALESCE(INSTT_ID, '')) = TRIM(#{insttId})
AND ENTRPRS_SE_CODE = #{entrprsSeCode}
AND ENTRPRS_MBER_STTUS LIKE #{sbscrbSttus}
AND ENTRPRS_MBER_ID LIKE '%' || #{searchKeyword} || '%'
AND APPLCNT_NM LIKE '%' ||#{searchKeyword}|| '%'
AND CMPNY_NM LIKE '%' ||#{searchKeyword}|| '%'
AND ( ENTRPRS_MBER_ID LIKE '%' || #{searchKeyword} || '%' OR APPLCNT_NM LIKE '%' || #{searchKeyword} || '%' OR CMPNY_NM LIKE '%' || #{searchKeyword} || '%' )
ORDER BY SBSCRB_DE DESC ) TB ) Z WHERE rn BETWEEN #{firstIndex} + 1 AND #{firstIndex} + #{recordCountPerPage}

SELECT COUNT(1) totcnt FROM COMTNENTRPRSMBER WHERE 1=1
AND PROJECT_ID = #{projectId}
AND TRIM(COALESCE(INSTT_ID, '')) = TRIM(#{insttId})
AND ENTRPRS_SE_CODE = #{entrprsSeCode}
AND ENTRPRS_MBER_STTUS LIKE #{sbscrbSttus}
AND ENTRPRS_MBER_ID LIKE '%' || #{searchKeyword} || '%'
AND APPLCNT_NM LIKE '%' || #{searchKeyword} || '%'
AND CMPNY_NM LIKE '%' || #{searchKeyword} || '%'
AND ( ENTRPRS_MBER_ID LIKE '%' || #{searchKeyword} || '%' OR APPLCNT_NM LIKE '%' || #{searchKeyword} || '%' OR CMPNY_NM LIKE '%' || #{searchKeyword} || '%' )

SELECT
    (SELECT COUNT(1)
     FROM COMVNUSERMASTER
     WHERE USER_ID = #{value})
  + (SELECT COUNT(1)
     FROM COMTNENTRPRSMBER
     WHERE ENTRPRS_MBER_ID = #{value}

       AND PROJECT_ID = #{projectId}

     ) AS totcnt

SELECT
    (SELECT COUNT(1)
     FROM COMVNUSERMASTER
     WHERE USER_EMAIL = #{value})
  + (SELECT COUNT(1)
     FROM COMTNENTRPRSMBER
     WHERE APPLCNT_EMAIL_ADRES = #{value}

       AND PROJECT_ID = #{projectId}

     ) AS totcnt

SELECT (
    SELECT COUNT(1) FROM COMTNINSTTINFO WHERE INSTT_NM = #{checkNm}

      AND PROJECT_ID = #{projectId}

) + (
    SELECT COUNT(1) FROM COMTNENTRPRSMBER WHERE CMPNY_NM = #{checkNm}

      AND PROJECT_ID = #{projectId}

) as totcnt

SELECT INSTT_ID AS rawInsttId, TRIM(INSTT_ID) AS insttId, INSTT_NM AS insttNm, ENTRPRS_SE_CODE AS entrprsSeCode, REPRSNT_NM AS reprsntNm, BIZRNO AS bizrno, ZIP AS zip, ADRES AS adres, DETAIL_ADRES AS detailAdres, BIZ_REG_FILE_PATH AS bizRegFilePath, INSTT_STTUS AS insttSttus, RJCT_RSN AS rjctRsn, TO_CHAR(RJCT_PNTTM, 'YYYY.MM.DD') as rjctPnttm, TO_CHAR(FRST_REGIST_PNTTM, 'YYYY.MM.DD HH24:MI:SS') as frstRegistPnttm, TO_CHAR(LAST_UPDT_PNTTM, 'YYYY.MM.DD HH24:MI:SS') as lastUpdtPnttm, CHARGER_NM AS chargerNm, CHARGER_EMAIL AS chargerEmail, CHARGER_TEL AS chargerTel FROM COMTNINSTTINFO
WHERE TRIM(INSTT_ID) = TRIM(#{insttId})
AND PROJECT_ID = #{projectId}
WHERE REPRSNT_NM = #{reprsntNm}
AND PROJECT_ID = #{projectId}
AND BIZRNO = #{bizrno}
ORDER BY LAST_UPDT_PNTTM DESC, FRST_REGIST_PNTTM DESC, INSTT_ID DESC LIMIT 1

SELECT MIN(ENTRPRS_MBER_ID) AS ENTRPRS_MBER_ID
FROM COMTNENTRPRSMBER
WHERE APPLCNT_NM = #{applcntNm}
  AND APPLCNT_EMAIL_ADRES = #{applcntEmailAdres}

  AND PROJECT_ID = #{projectId}

SELECT INSTT_STTUS
FROM COMTNINSTTINFO
WHERE BIZRNO = #{bizrno}

  AND PROJECT_ID = #{projectId}

ORDER BY LAST_UPDT_PNTTM DESC
LIMIT 1

