UPDATE COMTNINSTTINFO
INSTT_NM = #{insttNm}, REPRSNT_NM = #{reprsntNm}, ZIP = #{zip}, ADRES = #{adres}, DETAIL_ADRES = #{detailAdres}, BIZRNO = #{bizrno}, INSTT_STTUS = #{insttSttus}, RJCT_RSN = #{rjctRsn}, RJCT_PNTTM =
TO_DATETIME(#{rjctPnttm}, 'YYYY-MM-DD HH24:MI:SS')
NULL
, LAST_UPDT_PNTTM = SYSDATETIME, CHARGER_NM = #{chargerNm}, CHARGER_EMAIL = #{chargerEmail}, CHARGER_TEL = #{chargerTel}
, ENTRPRS_SE_CODE = #{entrprsSeCode}
, BIZ_REG_FILE_PATH = #{bizRegFilePath}
WHERE TRIM(INSTT_ID) = TRIM(#{insttId})
AND PROJECT_ID = #{projectId}
